import subprocess
import tempfile
import os

def syntax_check_python(code: str) -> bool:
    try:
        compile(code, "<string>", "exec")
        return True
    except SyntaxError:
        return False

def lint_score(code: str, language: str) -> float:
    """Returns 1.0 if clean, 0.0 if lint fails."""
    if language != "python":
        return 1.0   # skip for now
    with tempfile.NamedTemporaryFile(suffix=".py", delete=False, mode="w") as f:
        f.write(code)
        tmp = f.name
    try:
        result = subprocess.run(
            ["ruff", "check", "--select=E,F", "--quiet", tmp],
            capture_output=True, timeout=5,
        )
        return 1.0 if result.returncode == 0 else 0.5
    finally:
        os.unlink(tmp)

def rank_completions(
    candidates: list[str],
    ctx: CursorContext,
) -> str:
    scored = []
    for c in candidates:
        full = ctx.prefix + c + ctx.suffix
        if not syntax_check_python(full):
            continue
        score = lint_score(full, ctx.language)
        scored.append((score, c))

    if not scored:
        return candidates[0] if candidates else ""
    scored.sort(reverse=True)
    return scored[0][1]
